sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading)
        return;

    g_form.clearOptions('mode0');

    g_form.addOption(
        'mode0',
        '',
        '-- None --'
    );

    if (newValue == 'dell') {

        g_form.addOption('mode0', 'Latitude', 'Latitude');
        g_form.addOption('mode0', 'Inspiron', 'Inspiron');
        g_form.addOption('mode0', 'XPS', 'XPS');
    }

    else if (newValue == 'hp') {

        g_form.addOption('mode0', 'Pavilion', 'Pavilion');
        g_form.addOption('mode0', 'EliteBook', 'EliteBook');
        g_form.addOption('mode0', 'Victus', 'Victus');
    }

    else if (newValue == 'apple') {

        g_form.addOption('mode0', 'MacBook Air', 'MacBook Air');
        g_form.addOption('mode0', 'MacBook Pro', 'MacBook Pro');
        g_form.addOption('mode0', 'iMac', 'iMac');
    }

    else if (newValue == 'lenovo') {

        g_form.addOption('mode0', 'ThinkPad', 'ThinkPad');
        g_form.addOption('mode0', 'IdeaPad', 'IdeaPad');
        g_form.addOption('mode0', 'Legion', 'Legion');
    }

    else if (newValue == 'asus') {

        g_form.addOption('mode0', 'VivoBook', 'VivoBook');
        g_form.addOption('mode0', 'ZenBook', 'ZenBook');
        g_form.addOption('mode0', 'ROG', 'ROG');
    }

    else if (newValue == 'acer') {

        g_form.addOption('mode0', 'Aspire', 'Aspire');
        g_form.addOption('mode0', 'Nitro', 'Nitro');
        g_form.addOption('mode0', 'Predator', 'Predator');
    }

    else if (newValue == 'microsoft') {

        g_form.addOption('mode0', 'Surface Laptop', 'Surface Laptop');
        g_form.addOption('mode0', 'Surface Pro', 'Surface Pro');
        g_form.addOption('mode0', 'Surface Book', 'Surface Book');
    }

    else if (newValue == 'samsung') {

        g_form.addOption('mode0', 'Galaxy Book4', 'Galaxy Book4');
        g_form.addOption('mode0', 'Galaxy Book Pro', 'Galaxy Book Pro');
        g_form.addOption('mode0', 'Galaxy Book Ultra', 'Galaxy Book Ultra');
    }
}
